public int active()
{
    int ret = next active();
    if(ETGACFParameters::find().EnableMandatoryFields == NoYes::Yes)
    {
        FormDataSource      salesAgreement_ds         = any2Object(this) as FormDataSource;
        salesAgreement_ds.object(fieldNum(InventDim, configId)).mandatory(true);
        salesAgreement_ds.object(fieldNum(InventDim, InventSizeId)).mandatory(true);
        salesAgreement_ds.object(fieldNum(InventDim, InventColorId)).mandatory(true);
        salesAgreement_ds.object(fieldNum(InventDim, InventStyleId)).mandatory(true);
        salesAgreement_ds.object(fieldNum(InventDim, InventSiteId)).mandatory(true);
        salesAgreement_ds.object(fieldNum(InventDim, InventLocationId)).mandatory(true);
        salesAgreement_ds.object(fieldNum(InventDim, wMSLocationId)).mandatory(true);
    }
    return ret;
}

public boolean validateWrite()
{
    boolean ret = next validateWrite();

    if (ETGACFParameters::find().EnableMandatoryFields == NoYes::Yes)
    {
        ret = ETGSalesAgreementMandatoryValidation::validateFormLines(this.formRun());
    }
    return ret;
}
